1	\chapter{Line bundles on schemes and the Picard group}
2	\label{chap:Picard_LineBundle}
3	
4	This chapter sets up the foundational Phase~B/C infrastructure: the type of \emph{line bundles} (invertible quasi-coherent sheaves) on a scheme $X$, the abelian-group structure under tensor product, and the pull-back functoriality. It is the smallest self-contained step toward the Picard scheme construction (Theorem~\ref{thm:Pic_representable}) and feeds the Jacobian gap chain.
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $\Pic_{C/k}$ in later phases.
7	
8	\section{Definition}
9	
10	\begin{definition}[Line bundle on a scheme]
11	  \label{def:Scheme_LineBundle}
12	  \lean{AlgebraicGeometry.Scheme.LineBundle}
13	  Let $X$ be a scheme. A \emph{line bundle} on $X$ is an invertible quasi-coherent $\mathcal O_X$-module: a sheaf $L$ of $\mathcal O_X$-modules that is quasi-coherent and locally free of rank $1$. Equivalently: an object of the category of $\mathcal O_X$-modules that is invertible with respect to the tensor product $- \otimes_{\mathcal O_X} -$ in the symmetric monoidal category of $\mathcal O_X$-modules.
14	\end{definition}
15	
16	\begin{remark}
17	  Mathlib has the category of $\mathcal O_X$-modules and the quasi-coherence typeclass. The combination ``invertible quasi-coherent sheaf'' is not pre-packaged; it is the content of this definition.
18	\end{remark}
19	
20	\section{Group structure under tensor product}
21	
22	\begin{theorem}[Picard group of a scheme]
23	  \label{thm:Scheme_Pic_commGroup}
24	  \lean{AlgebraicGeometry.Scheme.instCommGroupLineBundle}
25	  For every scheme $X$, the type of line bundles on $X$ (modulo isomorphism) carries a canonical commutative-group structure. The operation is tensor product over $\mathcal O_X$, the unit is the structure sheaf $\mathcal O_X$ itself, and the inverse of a line bundle $L$ is its $\mathcal O_X$-dual $L^\vee = \mathcal{H}om_{\mathcal O_X}(L, \mathcal O_X)$.
26	
27	  We denote this group by $\Pic(X)$ and call it the \emph{Picard group} of $X$.
28	\end{theorem}
29	
30	\begin{proof}
31	  \uses{def:Scheme_LineBundle}
32	  Tensor product of two invertible quasi-coherent sheaves is invertible quasi-coherent (locally on $X$ this reduces to the corresponding statement for invertible modules over commutative rings, which Mathlib has). The structure sheaf is the tensor unit. The dual sheaf is the inverse: $L \otimes_{\mathcal O_X} L^\vee \cong \mathcal O_X$ canonically. Commutativity and associativity descend from the symmetric monoidal structure on the category of $\mathcal O_X$-modules.
33	\end{proof}
34	
35	\section{Pull-back functoriality}
36	
37	\begin{theorem}[Pull-back of line bundles]
38	  \label{thm:Scheme_Pic_pullback}
39	  \lean{AlgebraicGeometry.Scheme.Pic.pullback}
40	  Let $f \colon X \to Y$ be a morphism of schemes. Pull-back of $\mathcal O_Y$-modules along $f$ restricts to a group homomorphism
41	  \[
42	    f^* \colon \Pic(Y) \;\to\; \Pic(X),\qquad L \;\mapsto\; f^* L \;:=\; f^{-1} L \otimes_{f^{-1}\mathcal O_Y} \mathcal O_X.
43	  \]
44	  Pull-back preserves invertibility, commutes with tensor product, and is functorial: $(\mathrm{id}_X)^* = \mathrm{id}_{\Pic(X)}$ and $(f \circ g)^* = g^* \circ f^*$.
45	\end{theorem}
46	
47	\begin{proof}
48	  \uses{thm:Scheme_Pic_commGroup}
49	  Mathlib has the tensor product of $\mathcal O_X$-modules and the pullback of sheaves of modules along a scheme morphism. Pull-back commutes with tensor product. Functoriality is the standard sheaf-pullback functoriality.
50	\end{proof}
51	
52	\section{Use in the project}
53	
54	The Picard group $\Pic(X)$ is the underlying \emph{set} (modulo isomorphism) of the Picard \emph{scheme} $\Pic_{C/k}$ in the curve case; the scheme structure adds a $k$-scheme of finite type representing the relative Picard functor $S \mapsto \Pic(C \times_k S) / \Pic(S)$.
55	
56	This chapter is therefore the gateway to:
57	\begin{itemize}
58	  \item Definition~\ref{def:Pic_functor} (Picard functor of $C/k$) --- quotient by $\Pic(S)$ uses Theorem~\ref{thm:Scheme_Pic_pullback}.
59	  \item Theorem~\ref{thm:Pic_representable} (representability of the Picard scheme) --- uses the full $\Pic$ machinery built here.
60	  \item Definition~\ref{def:ofCurve} (Abel--Jacobi map) --- defined via the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$, an explicit element of $\Pic(C \times C)$.

